appsmith.onReady(() => {
  handleEligibilityUpdate();
});
appsmith.onModelChange(() => {
  handleEligibilityUpdate();
});
function handleEligibilityUpdate() {
  const rawData = appsmith.model && appsmith.model.scriptData ? appsmith.model.scriptData : {};
  const persona = appsmith.model && appsmith.model.persona ? appsmith.model.persona : "Adult";
  const isMinor = persona.toLowerCase().includes("minor");
  const rootKey = Object.keys(rawData)[0];
  const scriptsMap = rootKey ? rawData[rootKey] : {};

  // Group PIIs by severity
  const sensitiveSet = new Set();
  const standardSet = new Set();
  Object.values(scriptsMap).forEach(scriptInfo => {
    const sensitivePIIs = scriptInfo["sensitive PIIs"] || [];
    const standardPIIs = scriptInfo.PIIs || [];
    sensitivePIIs.forEach(p => {
      if (p && p.trim()) sensitiveSet.add(p.trim());
    });
    standardPIIs.forEach(p => {
      if (p && p.trim()) standardSet.add(p.trim());
    });
  });
  const sensitiveArr = Array.from(sensitiveSet).sort();
  const standardArr = Array.from(standardSet).sort();
  const totalSignals = sensitiveArr.length + standardArr.length;

  // Update Top-Level Metrics
  document.getElementById("total-signals").innerText = totalSignals;
  document.getElementById("high-certainty-count").innerText = totalSignals;

  // Render Circular Findings
  renderGroupedFindings(sensitiveArr, standardArr, isMinor);
}
function renderGroupedFindings(sensitiveArr, standardArr, isMinor) {
  const container = document.getElementById('findings-list');
  if (!container) return;
  if (sensitiveArr.length === 0 && standardArr.length === 0) {
    container.innerHTML = `
            <div class="no-findings">
                <div class="no-findings-icon">✅</div>
                <div>No eligibility signals observed.</div>
            </div>`;
    return;
  }
  const findings = [];

  // Group 1: Sensitive PII
  if (sensitiveArr.length > 0) {
    const indicatorTags = sensitiveArr.map(p => `<code class="indicator-tag">${p}</code>`).join('');
    findings.push({
      severity: "critical",
      title: isMinor ? "ILLEGAL (COPPA): Highly Sensitive Data" : "Critical Exposure: Sensitive PII",
      description: `High-certainty sensitive data available for AI ingestion via Internal Proxy.<br><div style="margin-top:8px;"><strong>Exposed:</strong> ${indicatorTags}</div>`,
      count: sensitiveArr.length,
      percentage: 95
    });
  }

  // Group 2: Standard PII
  if (standardArr.length > 0) {
    const indicatorTags = standardArr.map(p => `<code class="indicator-tag">${p}</code>`).join('');
    const severityLvl = isMinor ? "critical" : "high"; // Escalate if COPPA applies

    findings.push({
      severity: severityLvl,
      title: isMinor ? "ILLEGAL (COPPA): Standard PII" : "Warning: Standard PII Exposure",
      description: `Personally identifiable information tracked and available for ingestion.<br><div style="margin-top:8px;"><strong>Exposed:</strong> ${indicatorTags}</div>`,
      count: standardArr.length,
      percentage: isMinor ? 90 : 70
    });
  }
  container.innerHTML = findings.map(f => createFindingItem(f)).join('');

  // Animate SVG Circles
  setTimeout(() => {
    document.querySelectorAll('.progress-ring').forEach(ring => {
      const percentage = ring.dataset.percentage;
      const offset = 163 - 163 * percentage / 100;
      ring.style.strokeDashoffset = offset;
    });
  }, 100);
}
function createFindingItem(finding) {
  return `
        <div class="finding-item">
            <div class="severity-circle ${finding.severity}">
                <svg viewBox="0 0 60 60">
                    <circle class="bg-ring" cx="30" cy="30" r="26"></circle>
                    <circle class="progress-ring" cx="30" cy="30" r="26" data-percentage="${finding.percentage}"></circle>
                </svg>
                <span class="severity-label ${finding.severity}">${finding.severity}</span>
            </div>
            <div class="finding-content">
                <div class="finding-title">${finding.title}</div>
                <div class="finding-description">${finding.description}</div>
            </div>
            <div class="finding-count ${finding.severity}">${finding.count} ${finding.count === 1 ? 'signal' : 'signals'}</div>
        </div>
    `;
}

